// Besuch in Workflow-Static-Data speichern
const data = $getWorkflowStaticData('global');
if (!data.visitors) data.visitors = [];

data.visitors.push({
  ts: new Date().toISOString(),
  page: $json.page || '/',
  referrer: $json.referrer || null,
  utm_source: $json.utm_source || null,
  utm_medium: $json.utm_medium || null,
  utm_campaign: $json.utm_campaign || null,
  org: $json.org || null,
  city: $json.city || null,
  region: $json.region || null,
  country: $json.country || null,
  hostname: $json.hostname || null,
  ip: $json.ip || null,
});

// Max. 2000 Eintraege behalten
if (data.visitors.length > 2000) {
  data.visitors = data.visitors.slice(-2000);
}

return [{ json: { ok: true } }];

const data = $getWorkflowStaticData('global');
const all = data.visitors || [];

// Letzte 7 Tage
const weekAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
const recent = all.filter(v => new Date(v.ts).getTime() > weekAgo);

// Alte Eintraege aufraaeumen
data.visitors = recent;

if (recent.length === 0) {
  return [{ json: { count: 0, subject: 'KITech – Keine Besucher diese Woche', html: '<p>Keine Besucher mit Consent diese Woche.</p>' } }];
}

// Orgs gruppieren
const orgMap = {};
for (const v of recent) {
  const key = v.org || v.hostname || 'Unbekannt';
  if (!orgMap[key]) orgMap[key] = { count: 0, loc: '', pages: [] };
  orgMap[key].count++;
  if (v.city && v.country) orgMap[key].loc = v.city + ', ' + v.country;
  if (v.page && !orgMap[key].pages.includes(v.page)) orgMap[key].pages.push(v.page);
}

// Referrer gruppieren
const refMap = {};
for (const v of recent) {
  let ref = 'Direktaufruf';
  if (v.referrer) { try { ref = new URL(v.referrer).hostname.replace('www.', ''); } catch {} }
  refMap[ref] = (refMap[ref] || 0) + 1;
}

// Top-Seiten
const pageMap = {};
for (const v of recent) {
  const p = v.page || '/';
  pageMap[p] = (pageMap[p] || 0) + 1;
}

// UTM-Kampagnen
const utmMap = {};
for (const v of recent) {
  if (v.utm_campaign) utmMap[v.utm_campaign] = (utmMap[v.utm_campaign] || 0) + 1;
}

// Sortieren
const sortedOrgs = Object.entries(orgMap).sort((a, b) => b[1].count - a[1].count).slice(0, 30);
const sortedRefs = Object.entries(refMap).sort((a, b) => b[1] - a[1]).slice(0, 8);
const sortedPages = Object.entries(pageMap).sort((a, b) => b[1] - a[1]).slice(0, 8);
const sortedUtm = Object.entries(utmMap).sort((a, b) => b[1] - a[1]);

// KW berechnen
const now = new Date();
const jan1 = new Date(now.getFullYear(), 0, 1);
const kw = Math.ceil(((now - jan1) / 86400000 + jan1.getDay() + 1) / 7);

// Datum formatieren
const fmt = d => new Date(d).toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: 'numeric' });

// Tabellenzeilen
const orgRows = sortedOrgs.map(([org, d]) =>
  '<tr><td style="padding:8px 12px;border-bottom:1px solid #f0f0f0;font-size:13px;">' + org + '</td><td style="padding:8px 12px;border-bottom:1px solid #f0f0f0;text-align:center;font-weight:600;color:#2563eb;font-size:13px;">' + d.count + '</td><td style="padding:8px 12px;border-bottom:1px solid #f0f0f0;color:#888;font-size:12px;">' + (d.loc || '–') + '</td><td style="padding:8px 12px;border-bottom:1px solid #f0f0f0;color:#888;font-size:12px;">' + d.pages.join(', ') + '</td></tr>'
).join('');

const refRows = sortedRefs.map(([ref, c]) =>
  '<tr><td style="padding:7px 12px;border-bottom:1px solid #f0f0f0;font-size:13px;">' + ref + '</td><td style="padding:7px 12px;border-bottom:1px solid #f0f0f0;text-align:center;font-weight:500;font-size:13px;">' + c + '</td></tr>'
).join('');

const pageRows = sortedPages.map(([page, c]) =>
  '<tr><td style="padding:7px 12px;border-bottom:1px solid #f0f0f0;font-family:monospace;font-size:12px;">' + page + '</td><td style="padding:7px 12px;border-bottom:1px solid #f0f0f0;text-align:center;font-weight:500;font-size:13px;">' + c + '</td></tr>'
).join('');

const utmRows = sortedUtm.length > 0 ? sortedUtm.map(([utm, c]) =>
  '<tr><td style="padding:7px 12px;border-bottom:1px solid #f0f0f0;font-size:13px;">' + utm + '</td><td style="padding:7px 12px;border-bottom:1px solid #f0f0f0;text-align:center;font-weight:500;font-size:13px;">' + c + '</td></tr>'
).join('') : '<tr><td colspan="2" style="padding:12px;color:#aaa;font-size:12px;text-align:center;">Keine UTM-Kampagnen diese Woche</td></tr>';

const html = '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;max-width:680px;margin:0 auto;padding:24px;color:#1a1a2e;background:#fff;">'
  + '<div style="background:linear-gradient(135deg,#1e40af,#0ea5e9);padding:24px 28px;border-radius:12px;margin-bottom:24px;">'
  + '<div style="font-size:12px;color:rgba(255,255,255,0.7);margin-bottom:4px;">KITech Software · kitech-software.de</div>'
  + '<h1 style="color:white;margin:0 0 6px;font-size:22px;font-weight:400;">Besucherreport KW ' + kw + '</h1>'
  + '<div style="color:rgba(255,255,255,0.8);font-size:13px;">' + fmt(weekAgo) + ' – ' + fmt(now) + '</div>'
  + '</div>'
  + '<table style="width:100%;border-collapse:collapse;margin-bottom:28px;"><tr>'
  + '<td style="text-align:center;padding:16px;background:#f0f7ff;border-radius:8px;"><div style="font-size:32px;font-weight:600;color:#2563eb;">' + recent.length + '</div><div style="font-size:12px;color:#666;margin-top:2px;">Besuche</div></td>'
  + '<td style="width:12px;"></td>'
  + '<td style="text-align:center;padding:16px;background:#f0f7ff;border-radius:8px;"><div style="font-size:32px;font-weight:600;color:#2563eb;">' + sortedOrgs.length + '</div><div style="font-size:12px;color:#666;margin-top:2px;">Organisationen</div></td>'
  + '<td style="width:12px;"></td>'
  + '<td style="text-align:center;padding:16px;background:#f0f7ff;border-radius:8px;"><div style="font-size:32px;font-weight:600;color:#2563eb;">' + sortedRefs.length + '</div><div style="font-size:12px;color:#666;margin-top:2px;">Traffic-Quellen</div></td>'
  + '</tr></table>'
  + '<h2 style="font-size:14px;font-weight:600;color:#1e40af;border-left:3px solid #2563eb;padding-left:10px;margin-bottom:12px;text-transform:uppercase;letter-spacing:.5px;">Unternehmen &amp; Organisationen</h2>'
  + '<table style="width:100%;border-collapse:collapse;margin-bottom:28px;"><thead><tr style="background:#f8faff;"><th style="padding:8px 12px;text-align:left;font-size:11px;color:#888;font-weight:500;">Organisation / ISP</th><th style="padding:8px 12px;text-align:center;font-size:11px;color:#888;font-weight:500;">Besuche</th><th style="padding:8px 12px;text-align:left;font-size:11px;color:#888;font-weight:500;">Standort</th><th style="padding:8px 12px;text-align:left;font-size:11px;color:#888;font-weight:500;">Seiten</th></tr></thead><tbody>' + orgRows + '</tbody></table>'
  + '<table style="width:100%;border-collapse:collapse;margin-bottom:28px;"><tr><td style="width:48%;vertical-align:top;">'
  + '<h2 style="font-size:14px;font-weight:600;color:#1e40af;border-left:3px solid #2563eb;padding-left:10px;margin-bottom:12px;text-transform:uppercase;letter-spacing:.5px;">Traffic-Quellen</h2>'
  + '<table style="width:100%;border-collapse:collapse;"><tbody>' + refRows + '</tbody></table>'
  + '</td><td style="width:4%;"></td><td style="width:48%;vertical-align:top;">'
  + '<h2 style="font-size:14px;font-weight:600;color:#1e40af;border-left:3px solid #2563eb;padding-left:10px;margin-bottom:12px;text-transform:uppercase;letter-spacing:.5px;">Top Seiten</h2>'
  + '<table style="width:100%;border-collapse:collapse;"><tbody>' + pageRows + '</tbody></table>'
  + '</td></tr></table>'
  + '<h2 style="font-size:14px;font-weight:600;color:#1e40af;border-left:3px solid #2563eb;padding-left:10px;margin-bottom:12px;text-transform:uppercase;letter-spacing:.5px;">UTM-Kampagnen</h2>'
  + '<table style="width:100%;border-collapse:collapse;margin-bottom:28px;"><tbody>' + utmRows + '</tbody></table>'
  + '<div style="background:#f8f9fa;border-radius:8px;padding:12px 16px;font-size:11px;color:#999;text-align:center;">Automatisch erstellt von KITech n8n · Nur Besucher mit Analytics-Consent · ipinfo.io</div>'
  + '</body></html>';

return [{ json: { count: recent.length, subject: 'KITech Website – Besucherreport KW ' + kw + ' (' + recent.length + ' Besuche)', html } }];
